import React from 'react';
interface Props {
    pageContext: any;
}
const Context: React.FunctionComponent<Props> = ({ pageContext }) => {
    return (
        <section>
            <h1>{pageContext.title}</h1>
            <div dangerouslySetInnerHTML={{ __html: pageContext.content }} />
        </section>
    );
};

export default Context;
